async function main() {
  for (const item of updates) {
    const wordCount = item.description.split(/\s+/).length;
    const metaLen = item.metaDescription.length;
    console.log(`Updating: ${item.slug} (${wordCount} words, meta: ${metaLen} chars)`);
    await prisma.product.update({
      where: { slug: item.slug },
      data: {
        description: item.description,
        metaDescription: item.metaDescription,
      },
    });
  }
  console.log(`\nDone — ${updates.length} products updated.`);
}

main()
  .then(() => prisma.$disconnect())
  .catch((e) => {
    console.error(e);
    prisma.$disconnect();
    process.exit(1);
  });
